INSERT INTO albums (id, batchId, title, artist, year, genre, artworkUrl, itunesId, status, rating, notes, recommendedReason, listenedAt, createdAt) VALUES (1, 1, 'Cascade', 'Tourist', 2023, 'Electronic / Downtempo', NULL, NULL, 'skipped', NULL, NULL, 'Tourist sits in that same headphone-optimised space as Bonobo, layering organic textures with meticulous electronic production across a cohesive album arc. The melodic depth and spatial mix reward close listening in a way that feels closer to neo-classical than club music, which suits your crossover taste perfectly.', NULL, '2026-05-01 12:02:23');
INSERT INTO albums (id, batchId, title, artist, year, genre, artworkUrl, itunesId, status, rating, notes, recommendedReason, listenedAt, createdAt) VALUES (2, 1, 'The Whispering Room', 'Rival Consoles', 2022, 'Electronic / Ambient', NULL, NULL, 'skipped', NULL, NULL, 'Rival Consoles shares Gidge''s Nordic sense of restraint and atmosphere while pushing into more rhythmically complex, almost industrial territory that keeps things from feeling too passive. The production is meticulous and rewards headphone listening in the same way Jon Hopkins does, sitting between ambient drift and driven momentum.', NULL, '2026-05-01 12:02:24');
INSERT INTO albums (id, batchId, title, artist, year, genre, artworkUrl, itunesId, status, rating, notes, recommendedReason, listenedAt, createdAt) VALUES (3, 1, 'DJ Notoya Presents Tokyo Bliss - Japanese Funk, Boogie and City Pop From King Records 1974-88', 'DJ Notoya', 2025, 'R&B/Soul', 'https://is1-ssl.mzstatic.com/image/thumb/Music211/v4/30/a4/02/30a4023d-70ef-c4a4-70a1-d80bd1ce8321/Cover.jpg/600x600bb.jpg', '1789383562', 'skipped', NULL, NULL, 'Yotto operates in that interesting cousin space you gravitate toward, taking melodic house somewhere more cinematic and emotionally weighted than most of his peers. The album is a fully realised listening experience rather than a DJ tool, with the kind of high production sheen and melodic intelligence that links it to Bonobo and Gidge without sounding like either.', NULL, '2026-05-01 12:02:24');
INSERT INTO albums (id, batchId, title, artist, year, genre, artworkUrl, itunesId, status, rating, notes, recommendedReason, listenedAt, createdAt) VALUES (4, 2, 'Want to 1 2? (Bonus Track Version)', 'Machinedrum', 2009, 'Electronic', 'https://is1-ssl.mzstatic.com/image/thumb/Music211/v4/04/f3/ff/04f3ff5d-eca2-04e1-b991-a26a34d83dfc/354706.jpg/600x600bb.jpg', '1761296367', 'recommended', NULL, NULL, 'Richly textured electronic production that rewards close headphone listening, blending organic instrumentation with intricate rhythmic detail in the same space Bonobo occupies. It avoids the predictability of mainstream electronic music while still carrying strong melodic sensibility.', NULL, '2026-05-01 12:24:23');
INSERT INTO albums (id, batchId, title, artist, year, genre, artworkUrl, itunesId, status, rating, notes, recommendedReason, listenedAt, createdAt) VALUES (5, 2, 'Knock Knock', 'JSON Collett', 2023, 'Electronic / Ambient', 'http://coverartarchive.org/release/dc8e2b80-3c72-45f7-ab65-befbc7439072/26394846814-500.jpg', NULL, 'skipped', NULL, NULL, 'REPLACEMENT NEEDED - removing uncertain entry', NULL, '2026-05-01 12:24:26');
INSERT INTO albums (id, batchId, title, artist, year, genre, artworkUrl, itunesId, status, rating, notes, recommendedReason, listenedAt, createdAt) VALUES (7, 3, 'In a Safe Place', 'The Album Leaf', 2004, 'Alternative', 'https://is1-ssl.mzstatic.com/image/thumb/Music125/v4/37/20/d9/3720d983-4d25-f353-44af-d796ac45d498/s05.tjsjltyd.jpg/600x600bb.jpg', '15405970', 'listened', 10, 'love the nice melodies, wintery vibe and glitchy beats', 'Jimmy LaValle''s meticulous layering of orchestral textures and electronics sits precisely in the space between Jon Hopkins and Ólafur Arnalds, rewarding careful headphone listening with details that reveal themselves slowly. It''s a complete, arc-driven album that never overstays its welcome.', '2026-05-01 12:29:40', '2026-05-01 12:28:23');
INSERT INTO albums (id, batchId, title, artist, year, genre, artworkUrl, itunesId, status, rating, notes, recommendedReason, listenedAt, createdAt) VALUES (8, 3, 'Time Out (Dance Versions) - Single', 'Material', 1983, 'Electronic', 'https://is1-ssl.mzstatic.com/image/thumb/Music126/v4/78/40/d5/7840d588-8e5d-d104-fb7e-b7346563ad54/cover.jpg/600x600bb.jpg', '1717778143', 'recommended', NULL, NULL, 'Bill Laswell''s avant-dub masterpiece is the kind of left-field cousin to more mainstream electronic music that suits your preference for interesting outliers, with deep bass, unconventional structure and spatial production that opens up beautifully on headphones. It sits nowhere near pop but rewards repeated close listening.', NULL, '2026-05-01 12:28:23');
INSERT INTO albums (id, batchId, title, artist, year, genre, artworkUrl, itunesId, status, rating, notes, recommendedReason, listenedAt, createdAt) VALUES (9, 3, 'Immunity', 'Jon Hopkins', 2023, 'Electronic', 'https://is1-ssl.mzstatic.com/image/thumb/Music116/v4/78/c7/d5/78c7d516-d9a7-0cb9-1fee-0b53dfc74d96/887830017664.png/600x600bb.jpg', '1688995695', 'listened', 10, 'love the combo of beautiful melodies and hard techno', 'Since Hopkins is already a favourite, this is the album where his sound is most fully realised — a seamless journey from glacial ambient openings into aggressive, textured techno that covers both ends of your listening mood spectrum. It is widely considered one of the definitive headphone albums of the 2010s.', '2026-05-01 12:29:22', '2026-05-01 12:28:24');
INSERT INTO albums (id, batchId, title, artist, year, genre, artworkUrl, itunesId, status, rating, notes, recommendedReason, listenedAt, createdAt) VALUES (10, 4, 'Sublunar', 'Yotto', 2021, 'Electronic / Deep House', 'http://coverartarchive.org/release/19a21861-9417-475b-a9a8-b657c88636be/18736334442.jpg', NULL, 'skipped', NULL, NULL, 'Yotto crafts headphone-optimised deep house with the same organic warmth and melodic depth Bonobo is known for, but with a distinctly Nordic atmospheric quality. Sublunar rewards full-album listening with its carefully arc''d emotional journey from delicate ambient passages into driving, textured grooves.', NULL, '2026-05-01 12:30:18');
INSERT INTO albums (id, batchId, title, artist, year, genre, artworkUrl, itunesId, status, rating, notes, recommendedReason, listenedAt, createdAt) VALUES (11, 4, 'Equals', 'Rival Consoles', 2021, 'Electronic / Ambient Techno', 'http://coverartarchive.org/release/acff1731-81af-4046-aed1-aea7c841b16e/19117141303-500.jpg', NULL, 'listened', 10, 'love the electronic sounds. neoclassical but with machines', 'Rival Consoles builds rich, melodic electronic music with a strong compositional intelligence that aligns closely with Bonobo''s approach while pushing further into introspective, headphone-rewarding textures. The album balances rhythmic propulsion with airy, emotive spaces in a way that never feels repetitive.', '2026-05-01 12:31:19', '2026-05-01 12:30:23');
INSERT INTO albums (id, batchId, title, artist, year, genre, artworkUrl, itunesId, status, rating, notes, recommendedReason, listenedAt, createdAt) VALUES (12, 4, 'Surrender', 'Maggie Rogers', 2022, 'Alternative', 'https://is1-ssl.mzstatic.com/image/thumb/Music116/v4/f0/1d/1d/f01d1d02-8f85-3a9d-cd28-f7fed1010d02/22UMGIM04212.rgb.jpg/600x600bb.jpg', '1624951261', 'listened', 5, 'too pop', 'While pop-adjacent, Rogers sits firmly in the more interesting cousin category — her production is dense, layered, and rewards close headphone listening in a way mainstream pop rarely does. The album blends indie sensibility with electronic sheen that parallels Bonobo''s crossover appeal without ever feeling formulaic.', '2026-05-02 01:08:02', '2026-05-01 12:30:24');
INSERT INTO albums (id, batchId, title, artist, year, genre, artworkUrl, itunesId, status, rating, notes, recommendedReason, listenedAt, createdAt) VALUES (13, 5, 'In a Beautiful Place Out In the Country - EP', 'Boards of Canada', 2000, 'Electronic', 'https://is1-ssl.mzstatic.com/image/thumb/Music114/v4/6a/e0/f7/6ae0f701-d389-e8c4-986f-b5533ae612f8/mzi.bapcorpe.jpg/600x600bb.jpg', '282484650', 'recommended', NULL, NULL, 'Sits perfectly between your love of Jon Hopkins and Olafur Arnalds — warm, melodic, and deeply textural in a way that rewards headphone listening. It''s the more interesting cousin of ambient techno, never repeating itself, always unfolding.', NULL, '2026-05-01 12:37:24');
INSERT INTO albums (id, batchId, title, artist, year, genre, artworkUrl, itunesId, status, rating, notes, recommendedReason, listenedAt, createdAt) VALUES (14, 5, 'Vespertine', 'Björk', 2001, 'Electronic', 'https://is1-ssl.mzstatic.com/image/thumb/Music116/v4/32/d6/28/32d62861-0e24-2111-d3ed-3b54f23083d5/081227607265.jpg/600x600bb.jpg', '20920260', 'listened', 10, 'on of my favorite albums. glitchy, melodic', 'Microscopic headphone production built from ice, glitches, and orchestral strings — it''s neo-classical and electronic at once, which mirrors your Arnalds and Hopkins taste exactly. Intimate and strange, it''s nothing like mainstream pop despite its melodies being utterly captivating.', '2026-05-01 12:38:24', '2026-05-01 12:37:24');
INSERT INTO albums (id, batchId, title, artist, year, genre, artworkUrl, itunesId, status, rating, notes, recommendedReason, listenedAt, createdAt) VALUES (15, 5, 'Antidotes', 'Foals', 2008, 'Alternative', 'https://is1-ssl.mzstatic.com/image/thumb/Music114/v4/0a/6c/55/0a6c5521-8b09-8d8a-fa19-4f9b3ea06716/190295006389.jpg/600x600bb.jpg', '1551822348', 'recommended', NULL, NULL, 'If Interpol is in your library, Foals'' debut gives you that same post-punk tension but with twitchy, interlocking guitar patterns that feel genuinely unusual. It''s the kind of angular indie rock that rewards repeated close listening on headphones.', NULL, '2026-05-01 12:37:25');
INSERT INTO albums (id, batchId, title, artist, year, genre, artworkUrl, itunesId, status, rating, notes, recommendedReason, listenedAt, createdAt) VALUES (16, 6, 'In a Beautiful Place Out In the Country - EP', 'Boards of Canada', 2000, 'Electronic', 'https://is1-ssl.mzstatic.com/image/thumb/Music114/v4/6a/e0/f7/6ae0f701-d389-e8c4-986f-b5533ae612f8/mzi.bapcorpe.jpg/600x600bb.jpg', '282484650', 'recommended', NULL, NULL, 'Boards of Canada occupy that rare space where electronic music feels ancient and organic — warm, slightly degraded textures that blur the line between memory and invention. This EP rewards the kind of close, headphone listening you gravitate toward, with melodic fragments that haunt rather than resolve, sitting comfortably between your love of Jon Hopkins and the pastoral intimacy of Nick Drake.', NULL, '2026-05-02 00:25:04');
INSERT INTO albums (id, batchId, title, artist, year, genre, artworkUrl, itunesId, status, rating, notes, recommendedReason, listenedAt, createdAt) VALUES (17, 6, 'Hex;or Printing In the Infernal Method', 'Earth', 2005, 'Rock', 'https://is1-ssl.mzstatic.com/image/thumb/Music/ad/b1/34/mzi.kxksvpaw.jpg/600x600bb.jpg', '215873951', 'listened', 3, 'too prog rock', 'Earth''s pivot to sparse, cinematic guitar minimalism here produces something that feels like a Western scored by a neoclassical composer — glacially slow but viscerally heavy, rewarding your appetite for both contemplative atmosphere and physical weight. It occupies the same emotional register as Ólafur Arnalds but with a rawness that nods to your 70s-era preferences.', '2026-05-02 00:36:37', '2026-05-02 00:25:14');
INSERT INTO albums (id, batchId, title, artist, year, genre, artworkUrl, itunesId, status, rating, notes, recommendedReason, listenedAt, createdAt) VALUES (18, 6, 'Nonagon Infinity', 'King Gizzard & The Lizard Wizard', 2016, 'Alternative', 'https://is1-ssl.mzstatic.com/image/thumb/Music111/v4/61/a0/5d/61a05d18-b98a-bfff-6675-aeb6d258189e/cover.jpg/600x600bb.jpg', '1098855354', 'recommended', NULL, NULL, 'Designed as a seamlessly looping album with no beginning or end, this is a structurally adventurous piece of work that satisfies your appetite for the visceral and aggressive without sacrificing musical intelligence. Its relentless, hypnotic momentum has more in common with propulsive techno than conventional rock, making it one of the more interesting cousins in the psychedelic space.', NULL, '2026-05-02 00:25:14');
INSERT INTO albums (id, batchId, title, artist, year, genre, artworkUrl, itunesId, status, rating, notes, recommendedReason, listenedAt, createdAt) VALUES (19, 7, 'Kiasmos', 'Kiasmos', 2014, 'Electronic', 'https://is1-ssl.mzstatic.com/image/thumb/Music221/v4/60/f2/63/60f263ac-0348-2f85-30e7-2e4fb6655724/4050486109618_cover.jpg/600x600bb.jpg', '1451077320', 'listened', 10, 'one of my favorites', 'Kiasmos sits almost perfectly in the tension you love from Jon Hopkins — glacial, neoclassical piano melodies that gradually give way to pounding, minimal techno pulses, all wrapped in a distinctly Nordic, wintery atmosphere. It has real dynamic weight and emotional arc across a full album runtime, never settling into prettiness alone.', '2026-05-02 00:39:32', '2026-05-02 00:38:12');
INSERT INTO albums (id, batchId, title, artist, year, genre, artworkUrl, itunesId, status, rating, notes, recommendedReason, listenedAt, createdAt) VALUES (20, 7, 'Selected Ambient Works, Vol. II', 'Aphex Twin', 1994, 'Electronic', 'https://is1-ssl.mzstatic.com/image/thumb/Music124/v4/b4/59/cd/b459cd17-d4cb-6810-074f-2eef4f292430/mzi.obgacqgc.jpg/600x600bb.jpg', '280649372', 'recommended', NULL, NULL, 'Though slightly earlier than your preferred decades, this is one of the definitive texts for the atmospheric, introspective electronic music you love — vast, texturally rich soundscapes that carry genuine emotional intensity without a single guitar in sight. Its cold, expansive mood maps directly onto the wintery, immersive quality you prize in The Album Leaf.', NULL, '2026-05-02 00:38:13');
INSERT INTO albums (id, batchId, title, artist, year, genre, artworkUrl, itunesId, status, rating, notes, recommendedReason, listenedAt, createdAt) VALUES (21, 7, 'Dead Cities', 'The Future Sound of London', 1996, 'Pop', 'https://is1-ssl.mzstatic.com/image/thumb/Music125/v4/bc/35/b0/bc35b093-bad7-d9e5-ae52-58f3644dc72d/00724384206857.jpg/600x600bb.jpg', '714769679', 'listened', 6, 'a bit dated', 'Dead Cities is a deeply atmospheric, electroacoustic world-building record that layers glitchy, degraded textures over melodic fragments with real emotional weight — it anticipates much of what you love about the organic-meets-electronic aesthetic. The album rewards immersive, close listening and has a cinematic arc that keeps it dynamic rather than static.', '2026-05-02 00:39:56', '2026-05-02 00:38:14');
INSERT INTO albums (id, batchId, title, artist, year, genre, artworkUrl, itunesId, status, rating, notes, recommendedReason, listenedAt, createdAt) VALUES (22, 8, 'Collapsed in Sunbeams', 'Arlo Parks', 2021, 'Neo-Soul / Trip Hop', 'http://coverartarchive.org/release/e7150ce2-0f2e-4b0e-b968-5d8c5eead1c1/33375972729-500.jpg', NULL, 'listened', 8, 'i like this more than i thought because it''s a pop album', 'Parks weaves intimate, confessional songwriting over warm, unhurried production that carries a distinctly trip hop DNA updated for the 2020s. The beats are soft and organic yet carefully constructed, with a wintry emotional weight that should resonate with your love of introspective, melodically rich albums.', '2026-05-02 01:08:35', '2026-05-02 00:40:37');
INSERT INTO albums (id, batchId, title, artist, year, genre, artworkUrl, itunesId, status, rating, notes, recommendedReason, listenedAt, createdAt) VALUES (23, 8, 'Prioritise Pleasure', 'Self Esteem', 2021, 'Art Pop / Trip Hop', 'http://coverartarchive.org/release/21206029-1587-4530-82f1-0f1a3e1ce94a/33148624093-500.jpg', NULL, 'recommended', NULL, NULL, 'This album fuses lush orchestration with cool, precisely designed electronic textures in a way that feels genuinely forward-thinking rather than genre-orthodox. The production has real emotional intensity and melodic depth, anchoring its more dramatic moments in harmonic beauty rather than aggression.', NULL, '2026-05-02 00:40:40');
INSERT INTO albums (id, batchId, title, artist, year, genre, artworkUrl, itunesId, status, rating, notes, recommendedReason, listenedAt, createdAt) VALUES (24, 9, 'Ágætis Byrjun', 'Sigur Rós', 1999, 'Alternative', 'https://is1-ssl.mzstatic.com/image/thumb/Music114/v4/f7/34/fd/f734fd6c-aeca-8052-825c-706d1c665a8b/190296941856.jpg/600x600bb.jpg', '1447442814', 'listened', 8, NULL, 'Sigur Rós weave glacial, orchestral textures with delicate electronics and Jónsi''s falsetto creating something that feels both ancient and otherworldly — the wintry Nordic atmosphere will feel immediately familiar coming from Kiasmos. It rewards the kind of close, meditative listening you bring to your favourites, never rushing toward conventional song structures.', '2026-05-02 01:00:09', '2026-05-02 00:59:49');
INSERT INTO albums (id, batchId, title, artist, year, genre, artworkUrl, itunesId, status, rating, notes, recommendedReason, listenedAt, createdAt) VALUES (25, 9, 'The Glow, Pt. 2', 'The Microphones', 2001, 'Alternative', 'https://is1-ssl.mzstatic.com/image/thumb/Music/78/c6/06/mzi.wzxrrwjx.jpg/600x600bb.jpg', '483212192', 'recommended', NULL, NULL, 'Phil Elverum''s masterwork uses folk instrumentation as raw material for something genuinely avant-garde, where acoustic guitars and vocals are subjected to the same kind of textural, atmospheric treatment you love in glitch and experimental electronics. Its wintry, melancholic emotional world maps closely onto your taste profile while arriving from an entirely unexpected direction.', NULL, '2026-05-02 00:59:51');
INSERT INTO albums (id, batchId, title, artist, year, genre, artworkUrl, itunesId, status, rating, notes, recommendedReason, listenedAt, createdAt) VALUES (26, 9, 'Carrie & Lowell Live', 'Sufjan Stevens', 2017, 'Alternative', 'https://is1-ssl.mzstatic.com/image/thumb/Music91/v4/6b/20/6a/6b206ac1-e1b5-316d-334d-59df7b727fb6/656605613666.jpg/600x600bb.jpg', '1227779973', 'recommended', NULL, NULL, 'Sufjan strips his sound to its barest essentials here — fingerpicked guitar, hushed vocals, subtle electronic shimmer — producing something hauntingly intimate that connects directly to the neoclassical emotional precision you love in Rival Consoles. The album rewards patient, close listening and carries an emotional weight that never tips into sentimentality.', NULL, '2026-05-02 00:59:52');
INSERT INTO albums (id, batchId, title, artist, year, genre, artworkUrl, itunesId, status, rating, notes, recommendedReason, listenedAt, createdAt) VALUES (27, 10, 'Led Zeppelin IV (Remastered)', 'Led Zeppelin', 1971, 'Rock', 'https://is1-ssl.mzstatic.com/image/thumb/Music115/v4/5c/15/9b/5c159b27-95ca-b9a7-84e3-28e795fffd39/dj.kvkrpptq.jpg/600x600bb.jpg', '580708175', 'listened', 10, NULL, 'If any classic rock album can reach you, it''s this one — the atmospheric density of tracks like ''When the Levee Breaks'' and ''Going to California'' creates genuinely immersive worlds rather than just songs, with a textural darkness that echoes your taste for tension and release. The acoustic-electric contrast mirrors your love of organic and electronic interplay, even if the tools here are purely analogue.', '2026-05-02 01:20:21', '2026-05-02 01:20:11');
INSERT INTO albums (id, batchId, title, artist, year, genre, artworkUrl, itunesId, status, rating, notes, recommendedReason, listenedAt, createdAt) VALUES (28, 10, 'Rumours', 'Fleetwood Mac', 1977, 'Rock', 'https://is1-ssl.mzstatic.com/image/thumb/Music124/v4/4d/13/ba/4d13bac3-d3d5-7581-2c74-034219eadf2b/081227970949.jpg/600x600bb.jpg', '594061854', 'recommended', NULL, NULL, 'Rumours earns its place through the same quality you found in Arlo Parks — intimate, emotionally direct songwriting where the vulnerability feels genuinely felt rather than performed. The production is polished but never cold, and the emotional precision of Nicks and McVie''s vocals carries the same nakedness you''re drawn to in Holiday and Cooke.', NULL, '2026-05-02 01:20:12');
INSERT INTO albums (id, batchId, title, artist, year, genre, artworkUrl, itunesId, status, rating, notes, recommendedReason, listenedAt, createdAt) VALUES (29, 10, 'Astral Weeks', 'Van Morrison', 1968, 'Rock', 'https://is1-ssl.mzstatic.com/image/thumb/Music125/v4/88/91/1b/88911b7b-a63f-4624-3fb1-2976b628c59a/603497886340.jpg/600x600bb.jpg', '1031002336', 'recommended', NULL, NULL, 'This is arguably the classic rock-adjacent album most likely to genuinely move you — it sits at the intersection of jazz, folk, and soul with an improvisational, stream-of-consciousness intimacy that predates genre conventions rather than conforming to them. Morrison''s voice here has the same quality of emotional directness you''re seeking in Billie Holiday, and the album''s atmospheric, nocturnal warmth maps perfectly onto your wintry, immersive preferences.', NULL, '2026-05-02 01:20:13');
INSERT INTO albums (id, batchId, title, artist, year, genre, artworkUrl, itunesId, status, rating, notes, recommendedReason, listenedAt, createdAt) VALUES (30, 11, 'Kind of Blue', 'Miles Davis', 1959, 'Jazz', 'https://is1-ssl.mzstatic.com/image/thumb/Music/7f/9f/d6/mzi.vtnaewef.jpg/600x600bb.jpg', '268443092', 'listened', 9, 'pretty hard not to like it', 'The quintessential morning jazz album — unhurried, meditative, and built on mood rather than complexity for its own sake. Its modal approach creates an atmosphere closer to the ambient immersion you love than to conventional jazz structure, and the interplay between instruments has that organic warmth and purposeful tension you consistently gravitate toward.', '2026-05-02 13:39:14', '2026-05-02 13:19:27');
INSERT INTO albums (id, batchId, title, artist, year, genre, artworkUrl, itunesId, status, rating, notes, recommendedReason, listenedAt, createdAt) VALUES (31, 11, 'Getz/Gilberto', 'Stan Getz & João Gilberto', 1964, 'Jazz', 'https://is1-ssl.mzstatic.com/image/thumb/Music126/v4/54/04/b8/5404b8fd-3dbf-9fe1-0513-4611c4dec84e/06UMGIM14182.rgb.jpg/600x600bb.jpg', '1422655717', 'recommended', NULL, NULL, 'Tender, melodically rich, and suffused with a quiet melancholy that maps naturally onto your preference for introspective, wintery atmospheres — even if this one runs warmer. The textural intimacy of Gilberto''s guitar against Getz''s saxophone has a close-mic''d, micro-detailed quality that should appeal to the same instinct that drew you to Vespertine''s delicate orchestration.', NULL, '2026-05-02 13:19:27');
INSERT INTO albums (id, batchId, title, artist, year, genre, artworkUrl, itunesId, status, rating, notes, recommendedReason, listenedAt, createdAt) VALUES (32, 11, 'A Love Supreme', 'John Coltrane', 1965, 'Jazz', 'https://is1-ssl.mzstatic.com/image/thumb/Music114/v4/e5/24/aa/e524aacd-467b-66f3-8931-0fcd6750a4b9/08UMGIM07914.rgb.jpg/600x600bb.jpg', '1440713018', 'listened', 6, 'this one is tougher than miles davis. a little too free jazz for me. maybe i''ll get into free jazz in the future, i''m not ready yet', 'Built with the kind of conviction and emotional weight you prize above genre exercise — this is jazz as immersive, almost cinematic experience rather than a collection of performances. Its spiritual intensity and slowly unfolding structure feel closer to the post-rock and atmospheric music you love than to anything that would feel casual or functional.', '2026-05-02 14:26:42', '2026-05-02 13:19:28');
INSERT INTO albums (id, batchId, title, artist, year, genre, artworkUrl, itunesId, status, rating, notes, recommendedReason, listenedAt, createdAt) VALUES (33, 12, 'Emergence', 'Max Cooper', 2016, 'Downtempo', 'https://is1-ssl.mzstatic.com/image/thumb/Music124/v4/c6/b9/cb/c6b9cb86-2800-452f-5240-f8e0c8308ebb/cover.jpg/600x600bb.jpg', '1149398778', 'listened', 10, 'love max cooper. beats vs classical', 'Since you''re asking about Max Cooper specifically, starting with his most celebrated album makes sense — Emergence builds from delicate, neoclassical-influenced openings into driving, textural techno in exactly the way Jon Hopkins does on Immunity. The conceptual arc gives it the sense of careful, detailed construction you respond to strongly.', '2026-05-02 14:50:24', '2026-05-02 14:49:47');
INSERT INTO albums (id, batchId, title, artist, year, genre, artworkUrl, itunesId, status, rating, notes, recommendedReason, listenedAt, createdAt) VALUES (34, 12, 'Structures From Silence', 'Steve Roach', 1984, 'New Age', 'https://is1-ssl.mzstatic.com/image/thumb/Features/v4/fb/53/20/fb532046-51a0-e9e1-768d-2fbceb85c117/dj.hyhefhna.jpg/600x600bb.jpg', '606596052', 'listened', 3, 'too avant garde', 'Though slightly outside your preferred era, this is one of the most melodically anchored and emotionally warm ambient records ever made, avoiding the coldness or drone-without-payoff that leaves you cold. It rewards the kind of close, immersive listening you consistently gravitate toward.', '2026-05-02 15:03:40', '2026-05-02 14:49:49');
INSERT INTO albums (id, batchId, title, artist, year, genre, artworkUrl, itunesId, status, rating, notes, recommendedReason, listenedAt, createdAt) VALUES (35, 13, 'Solo', 'Nils Frahm', 2015, 'Ambient', 'https://is1-ssl.mzstatic.com/image/thumb/Music124/v4/96/cc/7b/96cc7b8c-e021-29b4-f3a8-fbaea382d389/4050486110133_cover.jpg/600x600bb.jpg', '1451164610', 'recommended', NULL, NULL, 'Like Max Cooper, Frahm operates in the space where classical structure meets electronic texture, building immense emotional weight through patient layering and precise production. One is his most intimate and headphone-rewarding album, full of the melodic depth and tactile sonic detail your taste profile consistently gravitates toward.', NULL, '2026-05-02 15:04:17');
INSERT INTO albums (id, batchId, title, artist, year, genre, artworkUrl, itunesId, status, rating, notes, recommendedReason, listenedAt, createdAt) VALUES (36, 14, 'II', 'Moderat', 2013, 'Electronic', 'https://is1-ssl.mzstatic.com/image/thumb/Music124/v4/95/84/53/9584530c-4ddb-5e12-64be-b78d10019814/dj.leykelbz.jpg/600x600bb.jpg', '828948276', 'listened', 10, 'love moderat', 'Moderat shares Max Cooper''s ability to build emotionally charged electronic music where melodic depth and rhythmic precision coexist without compromise, threading the needle between club architecture and introspective warmth. Their albums reward headphone listening with layered detail while maintaining the tension-and-release arc that defines your favourite records.', '2026-05-02 15:10:44', '2026-05-02 15:10:29');
INSERT INTO albums (id, batchId, title, artist, year, genre, artworkUrl, itunesId, status, rating, notes, recommendedReason, listenedAt, createdAt) VALUES (37, 14, 'Clark', 'Clark', 2014, 'Electronic', 'https://is1-ssl.mzstatic.com/image/thumb/Music3/v4/4a/f9/a0/4af9a087-c131-97ce-ec03-8a5127418524/WARP251_Packshot_2400.jpg/600x600bb.jpg', '917623350', 'recommended', NULL, NULL, 'Clark operates in the same space as Max Cooper and Jon Hopkins, constructing music that is simultaneously cerebral and visceral, with immaculate production that feels cinematic and precise rather than dated. His work earns its beauty through complexity, using glitchy textures and hard rhythmic frameworks as the scaffolding for genuine emotional payoff.', NULL, '2026-05-02 15:10:30');
INSERT INTO albums (id, batchId, title, artist, year, genre, artworkUrl, itunesId, status, rating, notes, recommendedReason, listenedAt, createdAt) VALUES (38, 14, 'The North Borders', 'Bonobo', 2013, 'Electronic', 'https://is1-ssl.mzstatic.com/image/thumb/Music221/v4/dd/ec/66/ddec66e4-9034-4409-f310-ee87da874487/5021392806198.png/600x600bb.jpg', '611171778', 'listened', 10, 'love bonobo', 'Bonobo brings the orchestral warmth and melodic richness you love in neoclassical-adjacent electronica, wrapping programmed rhythms in organic instrumentation that gives his records a timeless, cinematic quality. He sits at the same intersection of electronic and acoustic texture as The Album Leaf but with a sharper rhythmic propulsion that matches your preference for beat-driven atmosphere.', '2026-05-02 15:11:10', '2026-05-02 15:10:30');
INSERT INTO taste_profiles (id, summary, favoriteGenres, favoriteArtists, preferredDecades, moodPreferences, dislikedPatterns, albumsAnalyzed, lastUpdatedAt, isUpdating) VALUES (1, 'You gravitate toward music that exists in the space between the organic and the electronic — albums where synthesizers, glitchy textures, and programmed beats are woven together with genuine melodic warmth and emotional depth. Your highest-rated records share a common architecture: they feel simultaneously cerebral and immersive, often building atmosphere through layered sound design rather than traditional song structure. You''re drawn to artists who treat electronic production as a compositional language, not just a backdrop, and you respond strongly when that language is used to evoke something cinematic, introspective, or quietly euphoric. The tension between beauty and complexity is clearly a sweet spot for you — Max Cooper''s interplay of beats and classical structures, Jon Hopkins balancing tender melody against hard techno, Björk''s glitchy intimacy on Vespertine — these resonate because they hold opposites in balance without resolving the tension cheaply.
INSERT INTO recommendation_logs (id, batchId, level, event, detail, createdAt) VALUES (1, 13, 'info', 'claude_response', '{"prompt":"max cooper adjacent","suggestions_count":5,"suggestions":[{"title":"One","artist":"Nils Frahm","year":2015,"genre":"Neoclassical Electronic","reason":"Like Max Cooper, Frahm operates in the space where classical structure meets electronic texture, building immense emotional weight through patient layering and precise production. One is his most intimate and headphone-rewarding album, full of the melodic depth and tactile sonic detail your taste profile consistently gravitates toward."},{"title":"Shedding Skin","artist":"Bonobo","year":2005,"genre":"Downtempo Electronic","reason":"Bonobo shares Cooper''s instinct for orchestrating electronic music with cinematic sweep, and Shedding Skin is where his production feels most texturally rich and immersive, weaving live instrumentation through programmed rhythms without losing propulsion. If you love the beats-versus-classical tension in Emergence, this album delivers a warmer, more organic version of that same contrast."},{"title":"Emergent","artist":"Tycho","year":2022,"genre":"Electronic \/ Ambient","reason":"Tycho''s Emergent sits closer to the rhythmically propulsive end of his catalog, pairing shimmering melodic loops with driving electronic percussion in a way that feels timeless and precisely crafted. The production is immaculate and rewards repeated headphone listens in exactly the way your favorite albums do."},{"title":"Form","artist":"Ben Frost","year":2017,"genre":"Electronic \/ Experimental","reason":"Ben Frost builds music out of the same tension-and-release architecture you love in Jon Hopkins, using dense electronic textures and rhythmic propulsion to create something visceral and cinematic without sacrificing complexity. Form is his most structured and melodically accessible work, making it a natural entry point for a listener who wants cerebral electronic music with genuine emotional reward."},{"title":"Invisible Cities","artist":"Hauschka","year":2008,"genre":"Neoclassical Electronic","reason":"Hauschka''s prepared piano compositions share the glitchy intimacy of Vespertine while maintaining rhythmic momentum and a distinctly modern production aesthetic free of the dated quality that pulled you out of Dead Cities. Invisible Cities is richly detailed and emotionally evocative, sitting perfectly at the neoclassical-electronic intersection your taste orbits."}],"raw_response":"[\n  {\"title\": \"One\", \"artist\": \"Nils Frahm\", \"year\": 2015, \"genre\": \"Neoclassical Electronic\", \"reason\": \"Like Max Cooper, Frahm operates in the space where classical structure meets electronic texture, building immense emotional weight through patient layering and precise production. One is his most intimate and headphone-rewarding album, full of the melodic depth and tactile sonic detail your taste profile consistently gravitates toward.\"},\n  {\"title\": \"Shedding Skin\", \"artist\": \"Bonobo\", \"year\": 2005, \"genre\": \"Downtempo Electronic\", \"reason\": \"Bonobo shares Cooper''s instinct for orchestrating electronic music with cinematic sweep, and Shedding Skin is where his production feels most texturally rich and immersive, weaving live instrumentation through programmed rhythms without losing propulsion. If you love the beats-versus-classical tension in Emergence, this album delivers a warmer, more organic version of that same contrast.\"},\n  {\"title\": \"Emergent\", \"artist\": \"Tycho\", \"year\": 2022, \"genre\": \"Electronic \/ Ambient\", \"reason\": \"Tycho''s Emergent sits closer to the rhythmically propulsive end of his catalog, pairing shimmering melodic loops with driving electronic percussion in a way that feels timeless and precisely crafted. The production is immaculate and rewards repeated headphone listens in exactly the way your favorite albums do.\"},\n  {\"title\": \"Form\", \"artist\": \"Ben Frost\", \"year\": 2017, \"genre\": \"Electronic \/ Experimental\", \"reason\": \"Ben Frost builds music out of the same tension-and-release architecture you love in Jon Hopkins, using dense electronic textures and rhythmic propulsion to create something visceral and cinematic without sacrificing complexity. Form is his most structured and melodically accessible work, making it a natural entry point for a listener who wants cerebral electronic music with genuine emotional reward.\"},\n  {\"title\": \"Invisible Cities\", \"artist\": \"Hauschka\", \"year\": 2008, \"genre\": \"Neoclassical Electronic\", \"reason\": \"Hauschka''s prepared piano compositions share the glitchy intimacy of Vespertine while maintaining rhythmic momentum and a distinctly modern production aesthetic free of the dated quality that pulled you out of Dead Cities. Invisible Cities is richly detailed and emotionally evocative, sitting perfectly at the neoclassical-electronic intersection your taste orbits.\"}\n]"}', '2026-05-02 15:04:16');
