INSERT INTO recommendation_logs (id, batchId, level, event, detail, createdAt) VALUES (8, 14, 'info', 'pass1_artists', '{"prompt":"max cooper adjacent","count":5,"artists":[{"artist":"Moderat","reason":"Moderat shares Max Cooper''s ability to build emotionally charged electronic music where melodic depth and rhythmic precision coexist without compromise, threading the needle between club architecture and introspective warmth. Their albums reward headphone listening with layered detail while maintaining the tension-and-release arc that defines your favourite records."},{"artist":"Clark","reason":"Clark operates in the same space as Max Cooper and Jon Hopkins, constructing music that is simultaneously cerebral and visceral, with immaculate production that feels cinematic and precise rather than dated. His work earns its beauty through complexity, using glitchy textures and hard rhythmic frameworks as the scaffolding for genuine emotional payoff."},{"artist":"Bonobo","reason":"Bonobo brings the orchestral warmth and melodic richness you love in neoclassical-adjacent electronica, wrapping programmed rhythms in organic instrumentation that gives his records a timeless, cinematic quality. He sits at the same intersection of electronic and acoustic texture as The Album Leaf but with a sharper rhythmic propulsion that matches your preference for beat-driven atmosphere."},{"artist":"Emptyset","reason":"Emptyset push Max Cooper''s structural rigour toward something more austere and industrial, building tracks out of processed sound and pulsing sub-bass that rewards close listening with new textural detail on every pass. If you respond to the way Cooper uses hard electronic architecture to create transcendent moments, Emptyset offer a darker, more disciplined version of that same instinct."},{"artist":"Yosi Horikawa","reason":"Horikawa crafts immaculately produced electronic music where sound design itself becomes melody, each element placed with a precision that rewards headphone listening in the way your taste profile consistently favours. His records share Max Cooper''s textural richness and that sense of beauty earned through complexity, without ever drifting into pure ambient passivity."}]}', '2026-05-02 15:10:26');
INSERT INTO recommendation_logs (id, batchId, level, event, detail, createdAt) VALUES (9, 14, 'info', 'pass2_albums', '{"count":5,"suggestions":[{"artist":"Moderat","title":"II","year":2013,"genre":"Electronic","reason":"Moderat shares Max Cooper''s ability to build emotionally charged electronic music where melodic depth and rhythmic precision coexist without compromise, threading the needle between club architecture and introspective warmth. Their albums reward headphone listening with layered detail while maintaining the tension-and-release arc that defines your favourite records."},{"artist":"Clark","title":"Clark","year":2014,"genre":"Electronic","reason":"Clark operates in the same space as Max Cooper and Jon Hopkins, constructing music that is simultaneously cerebral and visceral, with immaculate production that feels cinematic and precise rather than dated. His work earns its beauty through complexity, using glitchy textures and hard rhythmic frameworks as the scaffolding for genuine emotional payoff."},{"artist":"Bonobo","title":"The North Borders","year":2013,"genre":"Electronic","reason":"Bonobo brings the orchestral warmth and melodic richness you love in neoclassical-adjacent electronica, wrapping programmed rhythms in organic instrumentation that gives his records a timeless, cinematic quality. He sits at the same intersection of electronic and acoustic texture as The Album Leaf but with a sharper rhythmic propulsion that matches your preference for beat-driven atmosphere."},{"artist":"Emptyset","title":"Recur","year":2013,"genre":"Industrial Techno","reason":"Emptyset push Max Cooper''s structural rigour toward something more austere and industrial, building tracks out of processed sound and pulsing sub-bass that rewards close listening with new textural detail on every pass. If you respond to the way Cooper uses hard electronic architecture to create transcendent moments, Emptyset offer a darker, more disciplined version of that same instinct."},{"artist":"Yosi Horikawa","title":"Wandering","year":2013,"genre":"Electronic","reason":"Horikawa crafts immaculately produced electronic music where sound design itself becomes melody, each element placed with a precision that rewards headphone listening in the way your taste profile consistently favours. His records share Max Cooper''s textural richness and that sense of beauty earned through complexity, without ever drifting into pure ambient passivity."}]}', '2026-05-02 15:10:29');
